package br.com.portfolio.ecommerce.order.application.usecase;
import br.com.portfolio.ecommerce.catalog.application.port.out.ProductRepository; import br.com.portfolio.ecommerce.customer.application.port.out.CustomerRepository; import br.com.portfolio.ecommerce.inventory.application.port.out.InventoryRepository; import br.com.portfolio.ecommerce.order.application.port.in.*; import br.com.portfolio.ecommerce.order.application.port.out.OrderRepository; import br.com.portfolio.ecommerce.order.domain.*; import br.com.portfolio.ecommerce.outbox.application.OutboxService; import br.com.portfolio.ecommerce.promotion.application.PromotionService; import br.com.portfolio.ecommerce.shipping.application.ShippingService; import br.com.portfolio.ecommerce.shared.domain.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.util.*;
@Service public class CheckoutService implements CheckoutUseCase { private final CustomerRepository customers; private final ProductRepository products; private final InventoryRepository inventory; private final OrderRepository orders; private final PromotionService promotion; private final ShippingService shipping; private final OutboxService outbox; public CheckoutService(CustomerRepository customers,ProductRepository products,InventoryRepository inventory,OrderRepository orders,PromotionService promotion,ShippingService shipping,OutboxService outbox){this.customers=customers;this.products=products;this.inventory=inventory;this.orders=orders;this.promotion=promotion;this.shipping=shipping;this.outbox=outbox;}
 @Transactional public Order checkout(CheckoutCommand c){ if(c.idempotencyKey()!=null){ var existing=orders.findByIdempotencyKey(c.idempotencyKey()); if(existing.isPresent()) return existing.get(); } var customer=customers.findById(c.customerId()).orElseThrow(()->new BusinessException("Cliente não encontrado")); customer.ensureActive(); List<OrderItem> items=new ArrayList<>(); for(var i:c.items()){ var p=products.findById(i.productId()).orElseThrow(()->new BusinessException("Produto não encontrado")); p.ensureSellable(); var stock=inventory.findByProductIdForUpdate(i.productId()).orElseThrow(()->new BusinessException("Estoque não encontrado")); stock.reserve(i.quantity()); inventory.save(stock); items.add(new OrderItem(p.id(),p.name(),i.quantity(),p.price())); } var subtotal=items.stream().map(OrderItem::total).reduce(Money.zero(), Money::add); var discount=promotion.calculateDiscount(c.couponCode(), subtotal); var shippingQuote=shipping.quote(c.shippingZipCode()); var order=Order.checkout(c.customerId(),items,discount,shippingQuote.price(),c.idempotencyKey()); var saved=orders.save(order); outbox.store(OrderCreatedEvent.of(saved)); return saved; } }
